Výber autentifikácie Zakomentovať alebo vybrať jeden správny spôsob autentifikácie v /etc/dovecot-conf.d/10-auth.conf
#!include auth-deny.conf.ext
#!include auth-master.conf.ext
#!include auth-oauth2.conf.ext
#!include auth-system.conf.ext
#!include auth-sql.conf.ext
#!include auth-ldap.conf.ext
#!include auth-passwdfile.conf.ext
!include auth-static.conf.ext\
Nastavenie autentifikácie Konfigurácia statického súbora /etc/dovecot-conf.d/conf.d/auth-static.conf.ext
auth_mechanisms = plain login
auth_allow_cleartext = no
passdb passwd-file {
passwd_file_path = /etc/dovecot/passdb
# passdb_default_password_scheme = SHA512-CRYPT
}
userdb static {
fields {
uid = vmail
gid = vmail
home = /var/vmail/%
mail_driver = maildir
mail_path = /var/vmail/%/Maildir # full mail location
}
}\
Vygenerovanie hesiel Hash hesla sa dá vygenerovať pomocou
doveadm pw -s SHA512-CRYPT
Nastavenie hesiel a účtov Vygenerované hash-e následne vložíme do statického súbora
cat /etc/dovecot/passdb
user@example.com:$6$ziZNc.6ZnITxQooC$8v2fltMQXFiTql04uGGszwwICwtJ1s27RxJaiW9wb1rm.4NUsKN7DLJ1A/joHifadEHGM.D2JIOwfphgI/WWF.

Krátky návod ako nainštalovať DHCP server na Debian. Je potom už jednoduché dorobiť boot-ovanie po sieti cez PXE.
Inštalácia apt install isc-dhcp-server
Konfigurácia # option definitions common to all supported networks...
option domain-name &quot;fordo.sk&quot;;
option domain-name-servers ns1.example.org, ns2.example.org;
default-lease-time 600;
max-lease-time 7200;
# The ddns-updates-style parameter controls whether or not the server will
# attempt to do a DNS update when a lease is confirmed. We default to the
# behavior of the version 2 packages ('none', since DHCP v2 didn't
# have support for DDNS.)
ddns-update-style none;
# If this DHCP server is the official DHCP server for the local
# network, the authoritative directive should be uncommented.
authoritative;
# Use this to send dhcp log messages to a different log file (you also
# have to hack syslog.conf to complete the redirection).
#log-facility local7;
option domain-name-servers 192.168.0.2, 8.8.8.8;
subnet 192.168.0.0 netmask 255.255.255.0 {
range 192.168.0.100 192.168.0.200;
option subnet-mask 255.255.255.0;
option broadcast-address 192.168.0.255;
option routers 192.168.0.1;
option domain-name-servers 192.168.0.2, 8.8.8.8;
next-server 192.168.0.2;
option bootfile-name &quot;pxelinux.0&quot;;
}
allow booting;
group {
next-server 192.168.0.2;
host tftpclient {
filename &quot;pxelinux.0&quot;;
}
}
host AW1_am4_asus {
hardware ethernet f0:2f:74:19:ff:ff;
fixed-address 192.168.0.10;
}
nastavenie na ktorom interface ma fungovat
vi /etc/default/isc-dhcp-server
# Show that we want to be the only DHCP server in this network:
authoritative;\
